import{_ as t,o as a,c as i,a1 as o}from"./chunks/framework.4YwckYnB.js";const h=JSON.parse('{"title":"Getting Started with RagNext","description":"","frontmatter":{},"headers":[],"relativePath":"guide/getting-started.md","filePath":"guide/getting-started.md"}'),r={name:"guide/getting-started.md"};function n(s,e,c,l,d,m){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="getting-started-with-ragnext" tabindex="-1">Getting Started with RagNext <a class="header-anchor" href="#getting-started-with-ragnext" aria-label="Permalink to &quot;Getting Started with RagNext&quot;">​</a></h1><p>Welcome to the <strong>RagNext Game Designer</strong>! This guide will introduce you to the core components of the editor and help you create your very first narrative action step script.</p><h2 id="core-concepts" tabindex="-1">Core Concepts <a class="header-anchor" href="#core-concepts" aria-label="Permalink to &quot;Core Concepts&quot;">​</a></h2><p>The RagNext editor organizes your adventure game using five principal structures:</p><ol><li><strong>Rooms</strong>: The physical locations within your game (e.g., <em>Small Bedroom</em>, <em>Transit Station</em>).</li><li><strong>Characters</strong>: Non-player characters (NPCs) that live in your rooms (e.g., <em>Professor Vance</em>, <em>Keith</em>).</li><li><strong>Objects/Items</strong>: Objects placed in rooms or held in player/NPC inventories (e.g., <em>Worn T-Shirt</em>, <em>Keycard</em>).</li><li><strong>Variables</strong>: Global variables that store state, numbers, flags, or time offsets (e.g., <code>HeroAge</code>, <code>SampleTime</code>).</li><li><strong>Timers</strong>: Background ticking entities that trigger action events at specific turn intervals.</li></ol><hr><h2 id="creating-action-scripts" tabindex="-1">Creating Action Scripts <a class="header-anchor" href="#creating-action-scripts" aria-label="Permalink to &quot;Creating Action Scripts&quot;">​</a></h2><p>Actions define the behavior and gameplay logic of your entities. An Action is built using a <strong>Visual Action Graph</strong> containing:</p><ul><li><strong>Start Node</strong>: Defines the trigger event (e.g. <em>User Clicked</em>, <em>Room Entered</em>, <em>Turn Tick</em>).</li><li><strong>Command Nodes</strong>: Actions that modify the state, play audio, move entities, or display text.</li><li><strong>Condition Nodes</strong>: Branches that check properties (e.g. gender, attributes, variables) and execute a <code>True</code> or <code>False</code> branch.</li></ul><hr><h2 id="dynamic-date-time-system" tabindex="-1">Dynamic Date &amp; Time System <a class="header-anchor" href="#dynamic-date-time-system" aria-label="Permalink to &quot;Dynamic Date &amp; Time System&quot;">​</a></h2><p>RagNext features a robust, type-aware datetime system.</p><h3 id="initializing-datetimes" tabindex="-1">Initializing Datetimes <a class="header-anchor" href="#initializing-datetimes" aria-label="Permalink to &quot;Initializing Datetimes&quot;">​</a></h3><p>When you create a Global Variable with the <code>Date &amp; Time</code> type hint, it will automatically validate your input format. If left empty, it will default to <code>DateTime.Now</code>.</p><h3 id="offsets-operations" tabindex="-1">Offsets &amp; Operations <a class="header-anchor" href="#offsets-operations" aria-label="Permalink to &quot;Offsets &amp; Operations&quot;">​</a></h3><p>You can increment or decrement datetime variables using the <strong>Increment</strong> (<code>var.inc</code>) or <strong>Decrement</strong> (<code>var.dec</code>) nodes. Specify the offset value using human-readable units:</p><ul><li><code>10 seconds</code> (or <code>10s</code>)</li><li><code>5 minutes</code> (or <code>5m</code>)</li><li><code>2 hours</code> (or <code>2h</code>)</li><li><code>1 day</code> (or <code>1d</code>)</li></ul><h3 id="autocomplete-placeholders" tabindex="-1">Autocomplete &amp; Placeholders <a class="header-anchor" href="#autocomplete-placeholders" aria-label="Permalink to &quot;Autocomplete &amp; Placeholders&quot;">​</a></h3><p>In description boxes and text nodes, you can output formatted date/time strings using double curly braces:</p><ul><li><code>{variables.MyTime}</code> $\\rightarrow$ Defaults to a player-friendly format (e.g., <code>October 31, 2026 8:00 AM</code>).</li><li><code>{variables.MyTime:date}</code> $\\rightarrow$ Outputs only the date (<code>October 31, 2026</code>).</li><li><code>{variables.MyTime:time}</code> $\\rightarrow$ Outputs only the time (<code>8:00 AM</code>).</li><li><code>{variables.MyTime:datetime}</code> $\\rightarrow$ Outputs the raw ISO-8601 string.</li></ul>',20)])])}const u=t(r,[["render",n]]);export{h as __pageData,u as default};
